const spell = context.item.data ?? {};
const selectedId = String(variables.selected_character_id ?? spell.character_id ?? "");

const cleanTechniqueName = name =>
  String(name ?? "")
    .replace(/^technique\s+/i, "")
    .trim()
    .replace(/^./, c => c.toUpperCase());

const cleanFormName = name =>
  String(name ?? "")
    .replace(/^form\s+/i, "")
    .trim()
    .replace(/^./, c => c.toUpperCase());

const characterAbilities = getRows(collections.character_abilities_list?.data);
const abilities = getRows(collections.abilities_list?.data);

const characterAbility = characterAbilities.find(a =>
  String(a.character_id ?? selectedId) === selectedId &&
  String(a.ability_id ?? a.id ?? a.ability?.id ?? "") === String(spell.technique_ability_id ?? "")
);

const ability = abilities.find(a =>
  String(a.id ?? "") === String(spell.technique_ability_id ?? "")
) ?? characterAbility ?? {};

const basePool = Number(
  characterAbility?.base_pool ??
  characterAbility?.ability_base_pool ??
  ability?.base_pool ??
  0
);

const ppSpent = Number(characterAbility?.pp_spent ?? 0);

const hasAdvantage = characterAbility?.has_advantage === true;
const hasDisadvantage = characterAbility?.has_disadvantage === true;

const advantageModifier = hasAdvantage && !hasDisadvantage ? 1 : 0;
const disadvantageModifier = hasDisadvantage && !hasAdvantage ? -1 : 0;

const wounds = getRows(collections.character_wounds?.data).find(w =>
  String(w.character_id ?? selectedId) === selectedId
) ?? {};

const woundPenalty =
  (wounds.light_locked === true && Number(wounds.light_max ?? 0) > 0 ? 1 : 0) +
  (wounds.moderate_locked === true && Number(wounds.moderate_max ?? 0) > 0 ? 1 : 0) +
  (wounds.grave_locked === true && Number(wounds.grave_max ?? 0) > 0 ? 1 : 0) +
  (wounds.critical_locked === true && Number(wounds.critical_max ?? 0) > 0 ? 1 : 0);

const pool = Math.max(
  basePool + ppSpent + advantageModifier + disadvantageModifier - woundPenalty,
  0
);

const characterTalents = getRows(collections.character_talents?.data);

const formRank = Number(
  characterTalents.find(t =>
    String(t.character_id ?? selectedId) === selectedId &&
    String(t.talent_id ?? t.id ?? "") === String(spell.form_talent_id ?? "")
  )?.current_rank ?? 0
);

const techniqueName = cleanTechniqueName(
  spell.technique_name ??
  ability.name ??
  "Technique"
);

const formName = cleanFormName(
  spell.form_name ??
  "Form"
);

return `${techniqueName} (${pool}d6) • ${formName} (${formRank})`;

