const condition = context.item.data;

const defs = collections.condition_definitions?.data ?? [];

const level = Number(condition?.condition_level ?? 0);

const def =
  defs.find(d =>
    d.condition_key === condition?.condition_key &&
    Number(d.level ?? 0) === level
  )
  ?? defs.find(d =>
    d.condition_key === condition?.condition_key &&
    Number(d.level ?? 0) === 0
  )
  ?? defs.find(d =>
    d.condition_key === condition?.condition_key
  );

return def?.label ?? condition?.condition_key ?? "";

const condition = context.item.data;

const defs = collections.condition_definitions?.data ?? [];

const key = condition?.condition_key;

if (!key) {
  return "Descrizione non disponibile.";
}

const sameDefs = defs
  .filter(d => d.condition_key === key)
  .sort((a, b) => Number(a.level ?? 0) - Number(b.level ?? 0));

if (sameDefs.length === 0) {
  return "Descrizione non disponibile.";
}

const mainDef =
  sameDefs.find(d => Number(d.level ?? 0) === Number(condition?.condition_level ?? 0))
  ?? sameDefs[0];

const general = String(mainDef.general_description ?? "").trim();

let text = "";

if (general) {
  text += "## Descrizione\n";
  text += general + "\n\n";
}

const normalLevels = sameDefs.filter(d => Number(d.level ?? 0) > 0);
const specialLevel = sameDefs.find(d => Number(d.level ?? 0) === 0);

if (normalLevels.length > 0) {
  for (const def of normalLevels) {
    const level = Number(def.level ?? 0);
    const desc = String(def.description ?? "").trim();

    if (!desc) continue;

    text += `## Livello ${level}\n`;
    text += desc + "\n\n";
  }
} else if (specialLevel) {
  const desc = String(specialLevel.description ?? "").trim();

  if (desc) {
    text += "## Effetto\n";
    text += desc + "\n\n";
  }
}

const isActive =
  condition?.is_active === true ||
  String(condition?.is_active ?? "").trim().toLowerCase() === "true";

if (isActive) {
  const sign = condition?.condition_sign;
  const target1 = condition?.condition_target_1;
  const target2 = condition?.condition_target_2;
  const source = condition?.source_label;
  const notes = condition?.notes;

  const details = [];

  if (sign) details.push(`Segno: ${sign}`);
  if (target1) details.push(`Bersaglio 1: ${target1}`);
  if (target2) details.push(`Bersaglio 2: ${target2}`);
  if (source) details.push(`Fonte: ${source}`);
  if (notes) details.push(`Note: ${notes}`);

  if (details.length > 0) {
    text += "## Dettagli attivi\n";
    text += details.map(d => `- ${d}`).join("\n");
  }
}

return text.trim() || "Descrizione non disponibile.";

