  : Array.isArray(raw?.data)
    ? raw.data
    : raw && typeof raw === "object"
      ? Object.values(raw)
      : [];

const title = value =>
  String(value ?? "")
    .replace(/_/g, " ")
    .trim()
    .replace(/^./, c => c.toUpperCase());

const c = context.item?.data ?? context.item ?? {};
const key = String(c.condition_key ?? "").trim();

const defs = getRows(collections.condition_definitions?.data);

const level = Number(c.condition_level ?? c.level ?? 0);

const def =
  defs.find(d =>
    String(d.condition_key ?? "") === key &&
    Number(d.level ?? 0) === level
  )
  ?? defs.find(d =>
    String(d.condition_key ?? "") === key &&
    Number(d.level ?? 0) === 0
  )
  ?? defs.find(d => String(d.condition_key ?? "") === key);

const baseLabel = def?.label ?? c.label ?? title(key) ?? "Condizione";

const wasActive =
  c.is_active === true ||
  String(c.is_active ?? "").toLowerCase() === "true";

const willActivate = !wasActive;

const source =
  c.source_name ??
  c.source_label ??
  "";

const targetLabels = {
  fisiche: "Fisiche",
  interazione: "Interazione",
  conoscenza: "Conoscenza",
  consapevolezza: "Consapevolezza",
  magiche: "Magiche",
  nuotare: "Nuotare",
  scalare: "Scalare",
  volare: "Volare",
  tempra: "Tempra",
  evasione: "Evasione",
  mente: "Mente",
  risolutezza: "Risolutezza"
};

const targets = [
  c.condition_target_1,
  c.condition_target_2
]
  .filter(Boolean)
  .map(t => targetLabels[t] ?? title(t));

const targetText = targets.length
  ? ` (${targets.join(", ")})`
  : "";

if (key === "concentrato") {
  if (willActivate) {
    return "Concentrato attivato. Fonte: Manuale.";
  }

  return source
    ? `Concentrato disattivato. Fonte precedente: ${source}.`
    : "Concentrato disattivato.";
}

const hasLevel = level > 0;
const sign = String(c.condition_sign ?? "").trim();

const levelText = hasLevel
  ? ` Lvl. ${sign === "-" ? "-" : ""}${level}`
  : "";

const label = `${baseLabel}${levelText}${targetText}`;

