const maneuver = context.item.data;

if (!maneuver) return "?";

if (maneuver.cost_type === "fixed") {
  return String(maneuver.fixed_pa_cost ?? "?");
}

if (
  maneuver.cost_type === "spell" ||
  maneuver.cost_type === "throw" ||
  maneuver.cost_type === "special"
) {
  return "?";
}

if (maneuver.cost_type !== "weapon") {
  return "?";
}

const getRows = (raw) => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : [];

const characters = getRows(collections.characters_detail?.data);
const inventory = getRows(collections.character_inventory_list?.data);
const templates = getRows(collections.item_templates?.data);
const uses = getRows(collections.character_combat_item_uses?.data);

const c = characters.find(
  c => String(c.id) === String(variables.selected_character_id)
);

if (!c) return "?";

const rightId = c.right_hand_item_id;
const leftId = c.left_hand_item_id;

const freeHandsCount =
  (rightId ? 0 : 1) +
  (leftId ? 0 : 1);

const equippedIds = [...new Set(
  [rightId, leftId]
    .filter(Boolean)
    .map(String)
)];

const equippedItems = inventory.filter(i =>
  equippedIds.includes(String(i.id))
);

const rissa = inventory.find(i =>
  String(i.character_id) === String(variables.selected_character_id) &&
  String(i.name ?? "").toLowerCase() === "rissa" &&
  i.can_attack === true
);

const candidateItems = [
  ...equippedItems,
  ...(freeHandsCount > 0 && rissa ? [rissa] : [])
];

function getTemplate(item) {
  return templates.find(t => String(t.id) === String(item.template_id));
}

function getUses(item) {
  return uses.find(u => String(u.inventory_item_id) === String(item.id));
}

function hasUses(item) {
  const itemUses = getUses(item);
  return itemUses && Number(itemUses.uses_current ?? 0) > 0;
}

function hasValidCost(item) {
  const cost = Number(getTemplate(item)?.weapon_pa);
  return Number.isFinite(cost) && cost > 0;
}

function canUseGenericWeaponManeuver(item) {
  if (!item?.can_attack) return false;
  if (!hasUses(item)) return false;
  if (!hasValidCost(item)) return false;

  const freeRequired = Number(item.hands_free_required ?? 0);
  if (freeHandsCount < freeRequired) return false;

  return true;
}

let validItems = candidateItems.filter(canUseGenericWeaponManeuver);

if (maneuver.maneuver_key === "counterattack") {
  validItems = validItems.filter(i =>
    String(i.equipped_range ?? "").toLowerCase() === "tocco"
  );
}

if (maneuver.maneuver_key === "opportunity_attack") {
  validItems = validItems.filter(i =>
    String(i.equipped_range ?? "").toLowerCase() === "tocco"
  );
}

if (maneuver.maneuver_key === "parry") {
  validItems = validItems.filter(i =>
    i.parry_mode === "weapon" ||
    i.parry_mode === "unarmed_only"
  );
}

if (validItems.length === 0) return "?";

const costs = validItems
  .map(i => Number(getTemplate(i)?.weapon_pa))
  .filter(n => Number.isFinite(n) && n > 0);

if (costs.length === 0) return "?";

const uniqueCosts = [...new Set(costs)];

if (uniqueCosts.length === 1) {
  return String(uniqueCosts[0]);
}

return "?";

