    .replace(/\b\w/g, c => c.toUpperCase());

const compact = text =>
  `<span style="white-space: nowrap;">${escapeHtml(text)}</span>`;

const joinPieces = pieces =>
  pieces.filter(Boolean).map(compact).join(' <span style="opacity:.65;">|</span> ');

const normalize = value => String(value ?? "").trim().toLowerCase();

const isNone = value => {
  const v = normalize(value);
  return !v || v === "none" || v === "nessuna" || v === "nessuno" || v === "null";
};

const inventorySingularities = getRows(collections.inventory_item_singularities?.data)
  .filter(s => String(s.inventory_item_id ?? "") === itemId);

const templateSingularities = getRows(collections.item_template_singularities?.data)
  .filter(s => String(s.item_template_id ?? "") === templateId);

const inventoryConditions = getRows(collections.inventory_item_conditions?.data)
  .filter(c => String(c.inventory_item_id ?? "") === itemId);

const templateConditions = getRows(collections.item_template_conditions?.data)
  .filter(c => String(c.item_template_id ?? "") === templateId);

const optionRows = [
  ...getRows(collections.singularity_select_options?.data),
  ...getRows(collections.singularity_select_options_cache?.data)
];

const shortLabel = (singularityId, levelKey) => {
  const key = normalize(levelKey);
  if (isNone(key)) return "";

  const row = optionRows.find(o =>
    String(o.singularity_id ?? "") === singularityId &&
    normalize(o.level_key ?? o.key) === key
  );

  const fullText = String(row?.option_text ?? "").trim();
  const match = fullText.match(/^\[[^\]]+\]\s*([^:]+):/);
  if (match?.[1]) return match[1].trim();

  return title(key);
};

const singularityKey = (singularityId, role = "standard") => {
  const inventoryRow = inventorySingularities.find(s =>
    String(s.singularity_id ?? "") === singularityId &&
    String(s.role ?? "standard") === role
  );

  if (inventoryRow?.level_key) return inventoryRow.level_key;

  const templateRow = templateSingularities.find(s =>
    String(s.singularity_id ?? "") === singularityId &&
    String(s.role ?? "standard") === role
  );

  return templateRow?.level_key ?? "";
};

const condition =
  inventoryConditions[0] ??
  templateConditions[0] ??
  {};

const conditionPiece = () => {
  const key = normalize(condition.condition_key);
  if (isNone(key)) return "";

  const name = condition.condition_name || title(key);
  const level = Number(condition.condition_level ?? 0);
  if (level <= 0) return "";

  const sign = condition.condition_sign === "-" ? "-" : "";

  const targetLabels = {
    fisiche: "Fisiche",
    interazione: "Interazione",
    conoscenza: "Conoscenza",
    consapevolezza: "Consapevolezza",
    magiche: "Magiche",
    nuotare: "Nuotare",
    scalare: "Scalare",
    volare: "Volare",
    tempra: "Tempra",
    evasione: "Evasione",
    mente: "Mente",
    risolutezza: "Risolutezza"
  };

  const targets = [
    condition.condition_target_1,
    condition.condition_target_2
  ]
    .filter(Boolean)
    .map(t => targetLabels[normalize(t)] ?? title(t));

  const targetText = targets.length
    ? ` (${targets.join(", ")})`
    : "";

  return `${name} Lvl. ${sign}${level}${targetText}`;
};

const timeUnitLabel = value => ({
  round: "Round",
  scene: "Scena",
  short_rest: "Riposo Breve",
  long_rest: "Riposo Lungo"
})[normalize(value)] ?? title(value);

const woundEffectLabel = value => {
  const v = normalize(value);
  if (v === "heal") return "Guarita";
  if (v === "damage") return "Inflitta";
  return "";
};

const itemType = normalize(item.item_type);
const itemSubtype = normalize(item.item_subtype);

const armorDefinition = getRows(collections.armor_definitions?.data)
  .find(a => String(a.id ?? "") === String(item.armor_definition_id ?? ""));

const armorWounds = getRows(collections.inventory_armor_wounds?.data)
  .find(w => String(w.inventory_item_id ?? "") === itemId);

const kitDefinitions = getRows(collections.inventory_kit_definitions?.data);

const kitLabel = kitKey => {
  const row = kitDefinitions.find(k =>
    String(k.kit_key ?? "") === String(kitKey ?? "")
  );
  return row?.label ?? title(kitKey);
};

if (itemType === "armor" || itemSubtype === "armor") {
  const label = armorDefinition?.armor_label ?? title(armorDefinition?.armor_category ?? "armatura");
  const tl = Number(item.item_tl ?? armorDefinition?.tl_min ?? 0);

  const woundPieces = [
    ["L", armorWounds?.light_max ?? armorDefinition?.light_max],
    ["M", armorWounds?.moderate_max ?? armorDefinition?.moderate_max],
    ["G", armorWounds?.grave_max ?? armorDefinition?.grave_max],
    ["C", armorWounds?.critical_max ?? armorDefinition?.critical_max]
  ]
    .map(([label, value]) => [label, Number(value ?? 0)])
    .filter(([, value]) => value > 0)
    .map(([label, value]) => `${label}${value}`);

  return joinPieces([
    `Armatura ${label}${tl ? ` (TL${tl})` : ""}: ${woundPieces.join(" | ") || "0"}`
  ]);
}

if (itemType === "shield" || itemSubtype === "shield") {
  return joinPieces([
    "Scudo",
    "Abilita Blocco quando e in Pronto"
  ]);
}

if (itemType === "kit" || itemSubtype === "kit" || item.kit_key) {
  return joinPieces([
    kitLabel(item.kit_key),
    "Ingombro: Medio"
  ]);
}

if (itemType === "component" || itemSubtype === "component" || item.component_kit_key) {
  return joinPieces([
    `Componenti per: ${kitLabel(item.component_kit_key)}`,
    "Ingombro: No"
  ]);
}

const volumeKey = singularityKey("volume");
const fatturaKey = singularityKey("fattura");
const portataKey = singularityKey("portata");
const durataKey = singularityKey("durata");
const bersaglioKey = singularityKey("bersaglio");
const minKey = singularityKey("intensita", "min");
const maxKey = singularityKey("intensita", "max");

const rawTags = item.substance_tags;
const savedTags = Array.isArray(rawTags)
  ? rawTags
  : String(rawTags ?? "")
      .replace(/[{}"]/g, "")
      .split(",")
      .map(t => t.trim())
      .filter(Boolean);

const inferredTags = [];
const condKey = normalize(condition.condition_key);

if (itemSubtype === "substance" || itemType === "substance") {
  if (!isNone(minKey) || !isNone(maxKey)) {
    if (normalize(item.substance_wound_effect_type) === "heal") inferredTags.push("arcana");
    else inferredTags.push("lesiva");
  }

  if (condKey === "abile") inferredTags.push("alterante");
  else if (condKey === "veloce") inferredTags.push("stimolante");
  else if (!isNone(condKey)) inferredTags.push("arcana");
}

const tagLabels = {
  alterante: "Alterante",
  lesiva: "Lesiva",
  stimolante: "Stimolante",
  arcana: "Arcana"
};

const tagOrder = ["alterante", "lesiva", "stimolante", "arcana"];

const tagKeys = [...new Set([...savedTags, ...inferredTags].map(normalize))]
  .filter(t => !isNone(t));

const sortedTagKeys = [
  ...tagOrder.filter(t => tagKeys.includes(t)),
  ...tagKeys.filter(t => !tagOrder.includes(t))
];

const substanceLabel = sortedTagKeys.length
  ? `Sostanza ${sortedTagKeys.map(t => tagLabels[t] ?? title(t)).join(", ")}`
  : "Sostanza";

const pieces = [];

if (itemSubtype === "substance" || itemType === "substance") {
  pieces.push(substanceLabel);
} else if (itemType === "common") {
  pieces.push("Oggetto Comune");
} else if (itemType === "powerful") {
  pieces.push("Oggetto Potente");
} else {
  pieces.push("Oggetto");
}

if (!isNone(volumeKey)) {
  pieces.push(`Volume: ${shortLabel("volume", volumeKey)}`);
}

if (!isNone(fatturaKey)) {
  pieces.push(`Fattura: ${shortLabel("fattura", fatturaKey)}`);
}

if (!isNone(portataKey)) {
  pieces.push(`Portata: ${shortLabel("portata", portataKey)}`);
}

if (!isNone(durataKey)) {
  const label = shortLabel("durata", durataKey);
  const unit = normalize(durataKey) === "prolungata"
    ? ` (${timeUnitLabel(item.effect_duration_unit)})`
    : "";

  pieces.push(`Durata: ${label}${unit}`);
}

if (!isNone(bersaglioKey)) {
  pieces.push(`Bersaglio: ${shortLabel("bersaglio", bersaglioKey)}`);
}

const effect = woundEffectLabel(item.substance_wound_effect_type ?? item.wound_effect_type);

if (!isNone(minKey) || !isNone(maxKey)) {
  if (effect) {
    pieces.push(`Ferita: ${effect}`);
  }

  if (!isNone(minKey)) {
    pieces.push(`Ferita min: ${shortLabel("intensita", minKey)}`);
  }

  if (!isNone(maxKey)) {
    pieces.push(`Ferita max: ${shortLabel("intensita", maxKey)}`);
  }
}

const cond = conditionPiece();
if (cond) {
  pieces.push(cond);
}

if (normalize(item.bulk_type) === "none") {
  pieces.push("Ingombro: No");
}

if (Number(item.item_tl ?? 0) > 0) {
  pieces.push(`TL: ${Number(item.item_tl)}`);
}

return joinPieces(pieces);

