const v = variables.parry_incoming_type;

if (v === "weapon_piccolo") return "piccolo";
if (v === "weapon_medio") return "medio";
if (v === "weapon_grande") return "grande";

return "";

const getRows = (raw) => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : [];

const characters = getRows(collections.characters_detail?.data);
const inventory = getRows(collections.character_inventory_list?.data);
const templates = getRows(collections.item_templates?.data);
const uses = getRows(collections.character_combat_item_uses?.data);

const c = characters.find(
  c => String(c.id) === String(variables.selected_character_id)
);

if (!c) return [];

const rightId = c.right_hand_item_id;
const leftId = c.left_hand_item_id;

const freeHandsCount =
  (rightId ? 0 : 1) +
  (leftId ? 0 : 1);

const incomingTypeRaw = variables.parry_incoming_type;

const incomingType = incomingTypeRaw === "unarmed"
  ? "unarmed"
  : "weapon";

const incomingVolume =
  incomingTypeRaw === "weapon_piccolo" ? "piccolo" :
  incomingTypeRaw === "weapon_medio" ? "medio" :
  incomingTypeRaw === "weapon_grande" ? "grande" :
  "";

const volumeRank = {
  piccolo: 1,
  medio: 2,
  grande: 3
};

const equippedIds = [...new Set(
  [rightId, leftId]
    .filter(Boolean)
    .map(String)
)];

const equippedItems = inventory.filter(i =>
  equippedIds.includes(String(i.id))
);

const rissa = inventory.find(i =>
  String(i.character_id) === String(variables.selected_character_id) &&
  String(i.name ?? "").toLowerCase() === "rissa" &&
  i.parry_mode === "unarmed_only"
);

const candidateItems = [
  ...equippedItems,
  ...(freeHandsCount > 0 && rissa ? [rissa] : [])
];

function getTemplate(item) {
  return templates.find(t => String(t.id) === String(item.template_id));
}

function getUses(item) {
  return uses.find(u => String(u.inventory_item_id) === String(item.id));
}

function canUseForParry(item) {
  if (!item) return false;

  const use = getUses(item);
  if (!use || Number(use.uses_current ?? 0) <= 0) return false;

  const template = getTemplate(item);
  const paCost = Number(template?.weapon_pa);
  if (!Number.isFinite(paCost) || paCost <= 0) return false;

  if (incomingType === "unarmed") {
    return item.parry_mode === "unarmed_only" && freeHandsCount > 0;
  }

  if (incomingType === "weapon") {
    if (item.parry_mode !== "weapon") return false;

    const itemRank = volumeRank[String(item.equipped_volume ?? "").toLowerCase()] ?? 0;
    const incomingRank = volumeRank[incomingVolume] ?? 0;

    return itemRank >= incomingRank;
  }

  return false;
}

return candidateItems
  .filter(canUseForParry)
  .map(item => {
    const template = getTemplate(item);
    const use = getUses(item);

    return {
      id: item.id,
      name: item.name,
      label: `${item.name} — ${Number(template?.weapon_pa ?? 0)} PA — ${Number(use?.uses_current ?? 0)}/${Number(use?.uses_max ?? 0)} usi`,
      paCost: Number(template?.weapon_pa ?? 0),
      ability: item.equipped_ability
    };
  });

