const desiredLocation = variables.split_item_location ?? "backpack";

if (desiredLocation !== "ready") {
  return desiredLocation;
}

function getSlots(item) {
  const quantity = item.quantity ?? 0;
  const bulk = item.bulk_type;

  if (quantity <= 0 || bulk === "none") return 0;
  if (bulk === "light") return Math.ceil(quantity / 5);
  if (bulk === "medium") return quantity * 2;
  if (bulk === "heavy") return quantity * 3;

  return 0;
}

const readyItems = (collections.character_inventory_list?.data ?? []).filter(
  item => item.location === "ready"
);

const currentReadySlots = readyItems.reduce(
  (sum, item) => sum + getSlots(item),
  0
);

const newQuantity = variables.split_amount ?? 0;
const newBulk = variables.split_item_bulk;

let newSlots = 0;

if (newQuantity <= 0 || newBulk === "none") newSlots = 0;
else if (newBulk === "light") newSlots = Math.ceil(newQuantity / 5);
else if (newBulk === "medium") newSlots = newQuantity * 2;
else if (newBulk === "heavy") newSlots = newQuantity * 3;

return currentReadySlots + newSlots > 5 ? "backpack" : "ready";

