en.code:
const getRows = raw => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : raw && typeof raw === "object"
      ? Object.values(raw)
      : [];

const rawValue = raw => {
  if (raw && typeof raw === "object") {
    return raw.value ?? raw.id ?? raw.key ?? raw.data?.id ?? raw.data?.value ?? "";
  }
  return raw ?? "";
};

const textValue = raw => String(rawValue(raw) ?? "").trim();
const normalizeChoice = raw => textValue(raw).toLowerCase();

const normalizeMagicType = raw => {
  const v = normalizeChoice(raw);
  if (v.includes("erm") || v === "hermetic") return "hermetic";
  if (v.includes("rit") || v === "ritual") return "ritual";
  return "spontaneous";
};

const isYes = raw => {
  const normalized = normalizeChoice(raw);
  return normalized === "yes" ||
    normalized === "true" ||
    normalized === "1" ||
    normalized === "si" ||
    normalized === "sì" ||
    normalized.includes("yes") ||
    normalized.includes("si") ||
    normalized.includes("sì");
};

const keyFrom = (raw, allowedKeys) => {
  const normalized = normalizeChoice(raw);
  if (!normalized) return "";
  const exact = allowedKeys.find(k => normalized === k);
  if (exact) return exact;
  return allowedKeys.find(k => normalized.includes(k)) ?? normalized;
};

const levels = getRows(collections.singularity_levels?.data);

const valueOf = (singularity, key) => {
  if (!key) return 0;
  const row = levels.find(s =>
    s.singularity_id === singularity &&
    s.key === key
  );
  return Number(row?.value ?? 0);
};

const magicType = normalizeMagicType(variables.magic_builder_magic_type);
const mode = normalizeChoice(variables.magic_builder_mode) || "custom";
const createsObject = isYes(variables.magic_builder_creates_physical_object);

const portataKey = keyFrom(variables.magic_builder_portata_key, [
  "personale", "tocco", "ridotta", "estesa", "vista", "remota"
]);

const durataKey = keyFrom(variables.magic_builder_durata_key, [
  "immediata", "round", "prolungata", "giorno", "mese", "anno"
]);

const bersaglioKey = keyFrom(variables.magic_builder_bersaglio_key, [
  "singolo", "gruppo", "stanza", "struttura", "confine"
]);

const woundKey = keyFrom(variables.magic_builder_wound_intensity_key || "nessuna", [
  "nessuna", "lieve", "moderata", "grave", "critica", "potente", "superiore"
]);

const volumeKey = keyFrom(variables.magic_builder_volume_key, [
  "piccolo", "medio", "grande", "enorme", "colossale"
]);

const fatturaKey = keyFrom(variables.magic_builder_fattura_key, [
  "rozza", "semplice", "comune", "raffinata", "esclusiva"
]);

let baseMag = 0;

if (mode === "counterspell") {
  baseMag += valueOf("portata", portataKey);
  baseMag += Math.max(Number(variables.magic_builder_counterspell_intensity ?? 0), 0);
} else {
  baseMag += valueOf("portata", portataKey);
  baseMag += valueOf("durata", durataKey);
  baseMag += valueOf("bersaglio", bersaglioKey);
  baseMag += valueOf("intensita", woundKey);
  baseMag += Number(variables.magic_builder_condition_level ?? 0);

  if (createsObject) {
    baseMag += valueOf("volume", volumeKey);
    baseMag += valueOf("fattura", fatturaKey);
  }
}

const finalMag = baseMag + (
  magicType === "spontaneous"
    ? 2
    : magicType === "ritual"
      ? 4
      : 0
);

const cd = finalMag <= 0
  ? 0
  : finalMag <= 2
    ? 1
    : finalMag <= 4
      ? 2
      : finalMag <= 6
        ? 3
        : 4;

const charTalents = getRows(collections.character_talents?.data);

const formRank = Number(
  charTalents.find(ct =>
    String(ct.talent_id) === String(variables.magic_builder_form_id)
  )?.current_rank ?? 0
);

const pa = Math.min(Math.max(finalMag, 2), 5);
const fp = Math.max(finalMag - formRank, 1);

const zeroWound = finalMag <= 0
  ? "Nessuna"
  : finalMag <= 2
    ? "Lieve"
    : finalMag <= 4
      ? "Moderata"
      : finalMag <= 6
        ? "Grave"
        : "Critica";

const baseText = `MAG: ${finalMag} | CD: ${cd} | PA: ${pa} | FP: ${fp} | Ferita a 0S: ${zeroWound}`;

if (magicType !== "hermetic") {
  return baseText;
}

const selectedId = String(variables.selected_character_id ?? "");
const editingSpellId = String(variables.selected_spell_id ?? "");

const spells = getRows(collections.character_spells_list?.data)
  .filter(s => String(s.character_id) === selectedId)
  .filter(s => s.magic_type === "hermetic")
  .filter(s => !editingSpellId || String(s.id) !== editingSpellId);

const used = spells.reduce((sum, s) => sum + Number(s.base_mag ?? 0), 0);

const detailRows = getRows(collections.characters_detail?.data);
const listRows = getRows(collections.characters_list?.data);

const character =
  detailRows.find(c => String(c.id) === selectedId)
  ?? listRows.find(c => String(c.id) === selectedId)
  ?? detailRows[0]
  ?? {};

const limit = Number(character.ingegno ?? 0);

return `${baseText} | Slot Lista: ${used + baseMag}/${limit}`;

