  : Array.isArray(raw?.data)
    ? raw.data
    : [];

const titleCase = text => String(text ?? "")
  .replace(/^technique\s+/i, "")
  .trim()
  .replace(/^./, c => c.toUpperCase());

const abilities = getRows(collections.abilities_list?.data);
const charAbilities = getRows(collections.character_abilities_list?.data);
const woundsRows = getRows(collections.character_wounds?.data);

const acquired = new Map(
  charAbilities
    .filter(ca => Number(ca.pp_spent ?? 0) > 0)
    .map(ca => [String(ca.ability_id), ca])
);

const wounds = woundsRows.find(w =>
  String(w.character_id) === String(variables.selected_character_id)
) ?? {};

const woundPenalty =
  (wounds.light_locked && Number(wounds.light_max ?? 0) > 0 ? 1 : 0) +
  (wounds.moderate_locked && Number(wounds.moderate_max ?? 0) > 0 ? 1 : 0) +
  (wounds.grave_locked && Number(wounds.grave_max ?? 0) > 0 ? 1 : 0) +
  (wounds.critical_locked && Number(wounds.critical_max ?? 0) > 0 ? 1 : 0);

return abilities
  .filter(a =>
    String(a.category ?? "").toLowerCase() === "magiche" &&
    acquired.has(String(a.id))
  )
  .sort((a, b) => titleCase(a.name).localeCompare(titleCase(b.name)))
  .map(a => {
    const ca = acquired.get(String(a.id)) ?? {};

    const advantage =
      ca.has_advantage === true && ca.has_disadvantage !== true ? 1 : 0;

    const disadvantage =
      ca.has_disadvantage === true && ca.has_advantage !== true ? -1 : 0;

    const pool = Math.max(
      Number(a.base_pool ?? 0) +
      Number(ca.pp_spent ?? 0) +
      advantage +
      disadvantage -
      woundPenalty,
      0
    );

    return {
      label: `${titleCase(a.name)} (${pool}d6)`,
      value: a.id
    };
  });

