};

const normalize = raw => String(rawValue(raw) ?? "").trim().toLowerCase();

const isYes = raw => {
  const v = normalize(raw);
  return v === "yes" ||
    v === "true" ||
    v === "1" ||
    v === "si" ||
    v === "sì" ||
    v.includes("yes") ||
    v.includes("si") ||
    v.includes("sì");
};

const keyFrom = (raw, allowedKeys) => {
  const v = normalize(raw);
  if (!v) return "";
  const exact = allowedKeys.find(k => v === k);
  if (exact) return exact;
  return allowedKeys.find(k => v.includes(k)) ?? v;
};

const magicRaw = normalize(variables.magic_builder_magic_type);

