  "immediata", "round", "prolungata", "giorno", "mese", "anno"
]);

const bersaglioKey = keyFrom(variables.magic_builder_bersaglio_key, [
  "singolo", "gruppo", "stanza", "struttura", "confine"
]);

const woundKey = keyFrom(variables.magic_builder_wound_intensity_key || "nessuna", [
  "nessuna", "lieve", "moderata", "grave", "critica", "potente", "superiore"
]);

const volumeKey = keyFrom(variables.magic_builder_volume_key, [
  "piccolo", "medio", "grande", "enorme", "colossale"
]);

const fatturaKey = keyFrom(variables.magic_builder_fattura_key, [
  "rozza", "semplice", "comune", "raffinata", "esclusiva"
]);

let baseMag = 0;

if (mode === "counterspell") {
  baseMag += valueOf("portata", portataKey);
  baseMag += Math.max(Number(variables.magic_builder_counterspell_intensity ?? 0), 0);
} else {
  baseMag += valueOf("portata", portataKey);
  baseMag += valueOf("durata", durataKey);
  baseMag += valueOf("bersaglio", bersaglioKey);
  baseMag += valueOf("intensita", woundKey);
  baseMag += Number(variables.magic_builder_condition_level ?? 0);

