      ? Object.values(raw)
      : [];

const rawValue = raw => {
  if (raw && typeof raw === "object") {
    return raw.value ?? raw.id ?? raw.key ?? raw.data?.id ?? raw.data?.value ?? raw.label ?? "";
  }
  return raw ?? "";
};

const key = raw => String(rawValue(raw) ?? "").trim().toLowerCase();

const levels = [
  ...getRows(collections.singularity_levels?.data),
  ...getRows(collections.singularity_select_options_cache?.data)
];

const valueOf = (singularity, levelKey) => {
  const k = key(levelKey);
  if (!k || k === "nessuna") return 0;

  const row = levels.find(l =>
    String(l.singularity_id ?? "") === singularity &&
    String(l.key ?? l.level_key ?? "").toLowerCase() === k
  );

  return Number(row?.value ?? row?.mag ?? row?.level_value ?? 0);
};

const selectedId = String(variables.selected_character_id ?? "");
const ctx = getRows(collections.character_creation_context?.data)
  .find(r => String(r.character_id ?? "") === selectedId) ?? {};

const worldTl = Math.min(12, Math.max(1, Number(ctx.campaign_tl ?? 1)));

const creationDetails = mag => {
  if (mag <= 2) return { cd: 1, time: "Ora" };
  if (mag <= 5) return { cd: 2, time: "Giorno" };
  if (mag <= 8) return { cd: 3, time: "Giorno" };
  if (mag <= 11) return { cd: 4, time: "Settimana" };
  if (mag <= 14) return { cd: 5, time: "Settimana" };
  if (mag <= 17) return { cd: 6, time: "Mese" };
  if (mag <= 20) return { cd: 7, time: "Mese" };
  if (mag <= 23) return { cd: 8, time: "Mese" };
  return { cd: 9, time: "Mesi/anni" };
};

const applyTl = (baseMag, objectTl) => {
  const base = Math.max(1, Number(baseMag ?? 1));
  const objTl = Math.min(12, Math.max(1, Number(objectTl ?? worldTl)));

  if (objTl <= worldTl) {
    return Math.max(1, base - Math.floor(worldTl / 2));
  }

  return Math.max(1, base + (objTl - worldTl));
};

const compact = text =>
  `<span style="white-space: nowrap;">${String(text ?? "")}</span>`;

const renderCreation = (baseMag, objectTl, kit = null, ability = null) => {
  const finalMag = applyTl(baseMag, objectTl);
  const details = creationDetails(finalMag);

  const pieces = [
    `Creazione: MAG ${finalMag}`,
    `CD: ${details.cd}`,
    `Cariche Kit: ${finalMag}`,
    `Tempo: ${details.time}`
  ];

  if (kit) pieces.push(`Kit: ${kit}`);
  if (ability) pieces.push(`Abilità: ${ability}`);

  return pieces
    .map(compact)
    .join(' <span style="opacity:.65;">|</span> ');
};

const armorCategoryFrom = raw => {
  const v = key(raw);

  if (["leggera", "light", "piccolo"].includes(v)) return "light";
  if (["media", "medium", "medio"].includes(v)) return "medium";
  if (["pesante", "heavy", "grande"].includes(v)) return "heavy";

  return "";
};

const armorCreation = (category, objectTl) => {
  const tl = Math.min(12, Math.max(1, Number(objectTl ?? 1)));

  if (tl <= 5) {
    if (category === "light") return { baseMag: 8, kit: "Fabbro", ability: "Forgia" };
    if (category === "medium") return { baseMag: 12, kit: "Fabbro", ability: "Forgia" };
    if (category === "heavy") return { baseMag: 15, kit: "Fabbro", ability: "Forgia" };
  }

  if (tl <= 9) {
    if (category === "light") return { baseMag: 9, kit: "Fabbro", ability: "Meccanica" };
    if (category === "medium") return { baseMag: 13, kit: "Fabbro", ability: "Meccanica" };
    if (category === "heavy") return { baseMag: 16, kit: "Fabbro", ability: "Meccanica" };
  }

  if (category === "light") return { baseMag: 10, kit: "Ingegnere", ability: "Meccanica" };
  if (category === "medium") return { baseMag: 13, kit: "Ingegnere", ability: "Meccanica" };
  if (category === "heavy") return { baseMag: 19, kit: "Ingegnere", ability: "Meccanica" };

  return null;
};

const type = key(variables.add_item_type);
const subtype = key(variables.add_item_subtype);

let baseMag = null;
let objectTl = Math.min(12, Math.max(1, Number(rawValue(variables.add_item_tl) || worldTl)));

if (type === "armor" || subtype === "armor") {
  const category = armorCategoryFrom(
    variables.add_armor_type ??
    variables.add_armor_volume
  );

  objectTl = Math.min(12, Math.max(1, Number(rawValue(variables.add_armor_tl) || worldTl)));

  const armor = armorCreation(category, objectTl);

  if (!armor) return "MAG creazione: - | Seleziona il tipo di armatura";

  return renderCreation(armor.baseMag, objectTl, armor.kit, armor.ability);
}

if (type === "shield" || subtype === "shield") {
  return renderCreation(8, 1, "Fabbro", "Forgia");
}

if (type === "kit" || subtype === "kit") {
  return compact("Creazione kit: Componenti 5 | Tempo: 1 ora");
}

if (type === "component" || type === "components" || subtype === "component" || subtype === "components") {
  return "";
}

if (type === "powerful" && (subtype === "weapon" || subtype === "custom")) {
  baseMag =
    valueOf("volume", variables.custom_powerful_volume) +
    valueOf("fattura", variables.custom_powerful_fattura) +
    valueOf("portata", variables.custom_powerful_portata) +
    valueOf("durata", variables.custom_powerful_durata) +
    valueOf("bersaglio", variables.custom_powerful_bersaglio) +
    valueOf("intensita", variables.custom_powerful_intensity_min) +
    valueOf("intensita", variables.custom_powerful_intensity_max);

  if (key(variables.custom_powerful_condition_key) !== "nessuna") {
    baseMag += Number(rawValue(variables.custom_powerful_condition_level) ?? 0);
  }
}

if (type === "common" && subtype === "custom") {
  baseMag =
    valueOf("volume", variables.add_item_volume) +
    valueOf("fattura", variables.add_item_fattura);
}

if (type === "powerful" && subtype === "substance") {
  baseMag =
    valueOf("volume", variables.substance_volume) +
    valueOf("fattura", variables.substance_fattura) +
    valueOf("portata", variables.substance_portata) +
    valueOf("durata", variables.substance_durata) +
    valueOf("bersaglio", variables.substance_bersaglio) +
    valueOf("intensita", variables.substance_intensity_min) +
    valueOf("intensita", variables.substance_intensity_max);

  if (key(variables.substance_condition_key) !== "nessuna") {
    baseMag += Number(rawValue(variables.substance_condition_level) ?? 0);
  }
}

if (baseMag === null || Number.isNaN(baseMag)) {
  return "MAG creazione: -";
}

return renderCreation(baseMag, objectTl);

