const normalize = raw => String(rawValue(raw) ?? "").trim().toLowerCase();

const escapeHtml = value => String(value ?? "")
  .replace(/&/g, "&amp;")
  .replace(/</g, "&lt;")
  .replace(/>/g, "&gt;")
  .replace(/"/g, "&quot;");

const compact = text =>
  `<span style="white-space: nowrap;">${escapeHtml(text)}</span>`;

const joinPieces = pieces =>
  pieces.filter(Boolean).map(compact).join(' <span style="opacity:.65;">|</span> ');

const keyFrom = (raw, allowedKeys) => {
  const normalized = normalize(raw);
  if (!normalized) return "";
  const exact = allowedKeys.find(k => normalized === k);
  if (exact) return exact;
  return allowedKeys.find(k => normalized.includes(k)) ?? normalized;
};

const levels = [
  ...getRows(collections.singularity_levels?.data),
  ...getRows(collections.singularity_select_options_cache?.data)
];

const valueOf = (singularity, key) => {
  if (!key) return 0;

  const row = levels.find(s =>
    String(s.singularity_id ?? "") === singularity &&
    String(s.key ?? s.level_key ?? "").toLowerCase() === key
  );

  return Number(row?.value ?? row?.mag ?? row?.level_value ?? 0);
};

const portataKey = keyFrom(variables.custom_powerful_portata, [
  "personale", "tocco", "ridotta", "estesa", "vista", "remota"
]);

const durataKey = keyFrom(variables.custom_powerful_durata, [
  "immediata", "round", "prolungata", "giorno", "mese", "anno"
]);

const bersaglioKey = keyFrom(variables.custom_powerful_bersaglio, [
  "singolo", "gruppo", "stanza", "struttura", "confine"
]);

const volumeKey = keyFrom(variables.custom_powerful_volume, [
  "piccolo", "medio", "grande", "enorme", "colossale"
]);

const fatturaKey = keyFrom(variables.custom_powerful_fattura, [
  "rozza", "semplice", "comune", "raffinata", "esclusiva"
]);

const minKey = keyFrom(variables.custom_powerful_intensity_min || "nessuna", [
  "nessuna", "lieve", "moderata", "grave", "critica", "potente", "superiore"
]);

const maxKey = keyFrom(variables.custom_powerful_intensity_max || "nessuna", [
  "nessuna", "lieve", "moderata", "grave", "critica", "potente", "superiore"
]);

const conditionKey = normalize(variables.custom_powerful_condition_key || "nessuna");
const conditionLevel = conditionKey && conditionKey !== "nessuna"
  ? Number(variables.custom_powerful_condition_level ?? 0)
  : 0;

const positiveMag =
  valueOf("volume", volumeKey) +
  valueOf("portata", portataKey) +
  valueOf("durata", durataKey) +
  valueOf("bersaglio", bersaglioKey) +
  valueOf("intensita", minKey) +
  valueOf("intensita", maxKey) +
  conditionLevel;

const fatturaReduction = valueOf("fattura", fatturaKey);

const mag = Math.max(0, positiveMag - fatturaReduction);

const pa = Math.max(1, Math.ceil(mag / 2));
const uses = Math.min(5, Math.max(1, 6 - pa));

return joinPieces([
  `Uso: MAG ${mag}`,
