const getRows = raw => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : raw && typeof raw === "object"
      ? Object.values(raw)
      : [];

const lowercaseWords = new Set([
  "a", "ad", "al", "allo", "alla", "ai", "agli", "alle",
  "da", "dal", "dallo", "dalla", "dai", "dagli", "dalle",
  "di", "del", "dello", "della", "dei", "degli", "delle",
  "e", "ed", "in", "nel", "nello", "nella", "nei", "negli", "nelle",
  "con", "su", "sul", "sullo", "sulla", "sui", "sugli", "sulle",
  "per", "tra", "fra"
]);

const titleCase = value =>
  String(value ?? "")
    .trim()
    .toLowerCase()
    .split(/\s+/)
    .map((word, index) => {
      if (index > 0 && lowercaseWords.has(word)) {
        return word;
      }

      return word.replace(/^\p{L}/u, c => c.toUpperCase());
    })
    .join(" ");

return getRows(collections.abilities_list?.data)
  .slice()
  .sort((a, b) =>
    titleCase(a.name).localeCompare(titleCase(b.name))
  )
  .map(a => ({
    label: titleCase(a.name),
    value: a.id
  }));

const getRows = raw => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : raw && typeof raw === "object"
      ? Object.values(raw)
      : [];

const title = value =>
  String(value ?? "")
    .replace(/_/g, " ")
    .trim()
    .replace(/^./, c => c.toUpperCase());

const byKey = new Map();

getRows(collections.condition_definitions?.data)
  .filter(c => c.is_special !== true)
  .filter(c => String(c.condition_key ?? "").trim() !== "")
  .forEach(c => {
    const key = String(c.condition_key ?? "").trim().toLowerCase();

    if (!key || key === "nessuna") return;

    if (!byKey.has(key)) {
      byKey.set(key, {
        label: c.label ?? title(key),
        value: key
      });
    }
  });

const rows = Array.from(byKey.values())
  .sort((a, b) => a.label.localeCompare(b.label));

return [
  { label: "Nessuna", value: "nessuna" },
  ...rows
];

