const getRows = raw => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : raw && typeof raw === "object"
      ? Object.values(raw)
      : [];

const rawValue = raw => {
  if (raw && typeof raw === "object") {
    return raw.value ?? raw.id ?? raw.key ?? raw.data?.id ?? raw.data?.value ?? raw.label ?? "";
  }
  return raw ?? "";
};

const normalize = raw => String(rawValue(raw) ?? "").trim().toLowerCase();

const escapeHtml = value => String(value ?? "")
  .replace(/&/g, "&amp;")
  .replace(/</g, "&lt;")
  .replace(/>/g, "&gt;")
  .replace(/"/g, "&quot;");

const compact = text =>
  `<span style="white-space: nowrap;">${escapeHtml(text)}</span>`;

const joinPieces = pieces =>
  pieces.filter(Boolean).map(compact).join(' <span style="opacity:.65;">|</span> ');

const selectedId = String(variables.selected_character_id ?? "");

const ctx = getRows(collections.character_creation_context?.data)
  .find(r => String(r.character_id ?? "") === selectedId) ?? {};

const worldTl = Number(ctx.campaign_tl ?? ctx.character_tl ?? 1);
const tl = Number(variables.add_armor_tl ?? worldTl);

const rawType = normalize(
  variables.add_armor_type ??
  variables.add_armor_volume
);

const armorCategory =
  ["light", "leggera", "leggere", "piccolo"].includes(rawType)
    ? "light"
    : ["medium", "media", "medie", "medio"].includes(rawType)
      ? "medium"
      : ["heavy", "pesante", "pesanti", "grande"].includes(rawType)
        ? "heavy"
        : "";

if (!armorCategory || !tl) {
  return "";
}

const armor = getRows(collections.armor_definitions?.data)
  .find(a =>
    String(a.armor_category ?? "") === armorCategory &&
    tl >= Number(a.tl_min ?? 0) &&
    tl <= Number(a.tl_max ?? 0)
  );

if (!armor) {
  return "";
}

const woundPieces = [
  ["L", armor.light_max],
  ["M", armor.moderate_max],
  ["G", armor.grave_max],
  ["C", armor.critical_max]
]
  .map(([label, value]) => [label, Number(value ?? 0)])
  .filter(([, value]) => value > 0)
  .map(([label, value]) => `${label}${value}`);

const bulkLabel = {
  none: "/",
  light: "Leggero",
  medium: "Medio",
  heavy: "Pesante"
}[String(armor.bulk_type ?? "").toLowerCase()] ?? armor.bulk_type;

return joinPieces([
  `${armor.armor_label ?? "Armatura"}: ${woundPieces.join(" | ") || "0"}`,
  `Ingombro: ${bulkLabel} (${Number(armor.bulk_value ?? 0)})`,
  `PA Max: ${Number(armor.pa_max_modifier ?? 0)}`,
  `Evasione: ${Number(armor.evasion_modifier ?? 0)}`,
  `Vigore min: ${Number(armor.vigor_required ?? 0)}`
]);

