const viewRaw = collections.inventory_transfer_requests_view?.data;

const requests = Array.isArray(viewRaw)
  ? viewRaw
  : Array.isArray(viewRaw?.data)
    ? viewRaw.data
    : [];

const req = requests.find(
  r => String(r.id) === String(variables.pending_transfer_request_id)
);

if (!req) return true;

const inventoryRaw = collections.character_inventory_list?.data;

const inventory = Array.isArray(inventoryRaw)
  ? inventoryRaw
  : Array.isArray(inventoryRaw?.data)
    ? inventoryRaw.data
    : [];

const receiverInventory = inventory.filter(
  i => String(i.character_id) === String(variables.selected_character_id)
);

const slotValue = {
  none: 0,
  light: 1,
  medium: 2,
  heavy: 3
};

const incomingSlots =
  (slotValue[req.bulk_type] ?? 0) * Math.max(Number(req.item_quantity ?? 1), 1);

if (req.item_type === "armor") {
  const hasArmorReady = receiverInventory.some(
    i => i.location === "ready" && i.item_type === "armor"
  );

  return hasArmorReady;
}

const usedSlots = receiverInventory
  .filter(i => i.location === "ready" && i.item_type !== "armor")
  .reduce((sum, i) => {
    return sum + (slotValue[i.bulk_type] ?? 0) * Math.max(Number(i.quantity ?? 1), 1);
  }, 0);

return usedSlots + incomingSlots > 5;

