const errors = [];

const volume = variables.edit_singularity_volume;
const min = variables.edit_singularity_ferita_min;
const max = variables.edit_singularity_ferita_max;

const conditionKey = variables.edit_condition_key;
const conditionSign = variables.edit_condition_sign;
const conditionLevel = Number(variables.edit_condition_level ?? 0);
const target1 = variables.edit_condition_target_1;
const target2 = variables.edit_condition_target_2;

const intensityValue = {
  nessuna: 0,
  lieve: 1,
  moderata: 2,
  grave: 3,
  critica: 4,
  potente: 5,
  superiore: 6
};

if (["enorme", "colossale"].includes(volume)) {
  errors.push("Non puoi salvare in inventario un oggetto con Volume Enorme o Colossale.");
}

if (
  min &&
  max &&
  intensityValue[max] < intensityValue[min]
) {
  errors.push("La Ferita massima non può essere inferiore alla Ferita minima.");
}

if (
  target1 &&
  target2 &&
  target1 === target2
) {
  errors.push("Target 1 e Target 2 non possono essere uguali.");
}

const conditionsWithoutSign = ["portato", "prono", "inefficiente", "trattenuto"];
const conditionNeedsSign =
  !!conditionKey && !conditionsWithoutSign.includes(conditionKey);

const conditionNeedsTarget1 =
  (conditionKey === "abile" && conditionLevel >= 1) ||
  (conditionKey === "mobile" && conditionLevel >= 1) ||
  (conditionKey === "protetto" && conditionLevel >= 4);

const conditionNeedsTarget2 =
  conditionKey === "abile" && conditionLevel >= 4;

if (conditionKey && conditionLevel <= 0) {
  errors.push("Se scegli una Condizione, devi scegliere anche il Livello.");
}

if (conditionNeedsSign && !conditionSign) {
  errors.push("Questa Condizione richiede un Segno.");
}

if (conditionNeedsTarget1 && !target1) {
  errors.push("Questa Condizione richiede Target 1.");
}

if (conditionNeedsTarget2 && !target2) {
  errors.push("Questa Condizione richiede Target 2.");
}

return errors[0] ?? "";

