const getRows = raw => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : raw && typeof raw === "object"
      ? Object.values(raw)
      : [];

const rawValue = raw => {
  if (raw && typeof raw === "object") {
    return raw.value
      ?? raw.id
      ?? raw.key
      ?? raw.label
      ?? raw.name
      ?? raw.data?.value
      ?? raw.data?.id
      ?? raw.data?.key
      ?? raw.data?.label
      ?? "";
  }

  return raw ?? "";
};

const normalize = raw =>
  String(rawValue(raw) ?? "").trim().toLowerCase();

const keyFrom = (raw, allowedKeys) => {
  const normalized = normalize(raw);
  if (!normalized) return "";

  const exact = allowedKeys.find(k => normalized === k);
  if (exact) return exact;

  return allowedKeys.find(k => normalized.includes(k)) ?? normalized;
};

const isYes = raw => {
  const normalized = normalize(raw);

  return normalized === "yes"
    || normalized === "true"
    || normalized === "1"
    || normalized === "si"
    || normalized === "sì"
    || normalized.includes("yes")
    || normalized.includes("si")
    || normalized.includes("sì");
};

const levels = getRows(collections.singularity_levels?.data);

const valueOf = (singularity, key) => {
  if (!key) return 0;

  const row = levels.find(s =>
    String(s.singularity_id ?? "") === singularity
    && String(s.key ?? "") === key
  );

  return Number(row?.value ?? 0);
};

const normalizeMagicType = raw => {
  const value = normalize(raw);

  if (value === "hermetic" || value === "ermetica" || value.includes("ermetica")) {
    return "hermetic";
  }

  if (value === "ritual" || value === "rituale" || value.includes("rituale")) {
    return "ritual";
  }

  return "spontaneous";
};

