  String(w.character_id) === String(variables.selected_character_id)
) ?? {};

const woundPenalty =
  (wounds.light_locked && Number(wounds.light_max ?? 0) > 0 ? 1 : 0) +
  (wounds.moderate_locked && Number(wounds.moderate_max ?? 0) > 0 ? 1 : 0) +
  (wounds.grave_locked && Number(wounds.grave_max ?? 0) > 0 ? 1 : 0) +
  (wounds.critical_locked && Number(wounds.critical_max ?? 0) > 0 ? 1 : 0);

