  .filter(a =>
    String(a.category ?? "").toLowerCase() === "magiche" &&
    acquired.has(String(a.id))
  )
  .sort((a, b) => titleCase(a.name).localeCompare(titleCase(b.name)))
  .map(a => {
    const ca = acquired.get(String(a.id)) ?? {};

    const advantage =
      ca.has_advantage === true && ca.has_disadvantage !== true ? 1 : 0;

    const disadvantage =
      ca.has_disadvantage === true && ca.has_advantage !== true ? -1 : 0;

    const pool = Math.max(
      Number(a.base_pool ?? 0) +
      Number(ca.pp_spent ?? 0) +
      advantage +
      disadvantage -
      woundPenalty,
      0
    );

