  portata.includes("remota") ||
  durata.includes("mese") ||
  durata.includes("anno") ||
  bersaglio.includes("confine")
)) {
  return "Portata Remota, Durata Mese/Anno e Bersaglio Confine sono possibili solo con Magia Rituale.";
}

const createsObject = isYes(variables.magic_builder_creates_physical_object);

if (mode !== "counterspell" && createsObject) {
