const conditionSign = String(rawValue(variables.magic_builder_condition_sign) ?? "").trim();
const target1 = String(rawValue(variables.magic_builder_condition_target_1) ?? "").trim();
const target2 = String(rawValue(variables.magic_builder_condition_target_2) ?? "").trim();

